 1	import React from 'react';
 2	
 3	import { StorageClassModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import { getSCSelectOptions } from '@kubevirt-utils/components/DiskModal/components/StorageClassAndPreallocation/utils/helpers';
 5	import InlineFilterSelect from '@kubevirt-utils/components/FilterSelect/InlineFilterSelect';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { Checkbox, Stack, StackItem } from '@patternfly/react-core';
 8	
 9	const UploadPVCFormStorageClass = ({
10	  applySP,
11	  setApplySP,
12	  setStorageClassName,
13	  storageClasses,
14	  storageClassName,
15	}) => {
16	  const { t } = useKubevirtTranslation();
17	
18	  return (
19	    <Stack hasGutter>
20	      <StackItem>
21	        <label className="control-label co-required">{t('StorageClass')}</label>
22	        <InlineFilterSelect
23	          options={getSCSelectOptions(storageClasses)}
24	          selected={storageClassName}
25	          setSelected={(scName: string) => setStorageClassName(scName)}
26	          toggleProps={{ placeholder: t('Select {{label}}', { label: StorageClassModel.label }) }}
27	        />
28	      </StackItem>
29	      <StackItem>
30	        <Checkbox
31	          description={t(
32	            'Use optimized access mode & volume mode settings from StorageProfile resource.',
33	          )}
34	          data-checked-state={applySP}
35	          data-test="apply-storage-provider"
36	          id="apply-storage-provider"
37	          isChecked={applySP}
38	          // isDisabled={!isSPSettingProvided}
39	          label={t('Apply optimized StorageProfile settings')}
40	          onChange={() => setApplySP((value) => !value)}
41	        />
42	      </StackItem>
43	    </Stack>
44	  );
45	};
46	
47	export default UploadPVCFormStorageClass;

